import React from 'react';

function App() {
  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center">
      <div className="text-center">
        <h1 className="text-4xl font-bold text-gray-900 mb-4">NPC Website</h1>
        <p className="text-lg text-gray-600">Welcome to NPC Professional Pest Control Services</p>
        <p className="text-sm text-gray-500 mt-2">Website is loading...</p>
      </div>
    </div>
  );
}

export default App;
